        if self.PREVIOUS_DECISION_SHA256 is not None:
            VAMMetadataOnlyReviewAddPREVIOUS_DECISION_SHA256(builder, PREVIOUS_DECISION_SHA256)
        VAMMetadataOnlyReview = VAMMetadataOnlyReviewEnd(builder)
        return VAMMetadataOnlyReview
